// === CONFIGURACION (editar antes de ejecutar) ===
const MODO_FECHA = 'FECHA_ESPECIFICA';                // 'HOY' o 'FECHA_ESPECIFICA'
const FECHA_ESPECIFICA = '2026-05-07';   // solo se usa si MODO_FECHA = 'FECHA_ESPECIFICA'
const EJECUTAR_DESCARGA = true;          // true = descargar audios, false = solo reportes
const VAPI_API_KEY = '484afd71-2703-4852-8580-9629620dde82';
const VAPI_ASSISTANT_PREVENTIVA = 'aa95f1ca-a21a-4445-b7ff-bc414774d805';
const VAPI_ASSISTANT_COBROS = 'dbb81b6f-8e6b-4b18-9db6-6a4fcf9dca37';

return items.map((item) => {
  const tz = 'America/Guayaquil';

  let forDate;
  if (MODO_FECHA === 'FECHA_ESPECIFICA') {
    forDate = FECHA_ESPECIFICA;
  } else {
    const nowLocal = new Date(new Date().toLocaleString('en-US', { timeZone: tz }));
    const yyyy = nowLocal.getFullYear();
    const mm = String(nowLocal.getMonth() + 1).padStart(2, '0');
    const dd = String(nowLocal.getDate()).padStart(2, '0');
    forDate = `${yyyy}-${mm}-${dd}`;
  }

  const yyyymmdd = forDate.replace(/-/g, '');

  item.json.cfg = {
    report: {
      tz,
      forDate,
      yyyymmdd,
      exportBasePath: './public_html/BANCO_SOLIDARIO',
      exportFolderPath: `./public_html/BANCO_SOLIDARIO/${yyyymmdd}`,
      cedente: 'BANCO SOLIDARIO',
      tipoCartera: 'Administrativo',
      canalGestion: 'VOZ IA',
      gestoresAsignados: '1',
      diasLaborados: '1',
      observaciones: ' ',
      ejecutarDescargaLlamadas: EJECUTAR_DESCARGA
    },
    vapi: {
      baseUrl: 'https://api.vapi.ai',
      apiKey: VAPI_API_KEY,
      assistants: {
        PREVENTIVA: VAPI_ASSISTANT_PREVENTIVA,
        COBROS: VAPI_ASSISTANT_COBROS
      }
    },
    agents: {
      COBROS: VAPI_ASSISTANT_COBROS,
      PREVENTIVA: VAPI_ASSISTANT_PREVENTIVA
    }
  };

  return item;
});

const cfg = $items('CONFIG INICIAL', 0, 0)[0].json.cfg;
const dd = cfg.report.yyyymmdd;

const safeCount = (nodeName) => {
  try {
    return $items(nodeName, 0, 0).length;
  } catch (e) {
    return 0;
  }
};

const prodRows = safeCount('CONSULTA PRODUCTIVIDAD (DIA)');
const gestRows = safeCount('CONSULTA GESTION (DIA)');

return [{
  json: {
    status: 'ok',
    fecha_reporte: cfg.report.forDate,
    carpeta_destino: cfg.report.exportFolderPath,
    archivo_productividad: `reporte_productividad_${dd}.xlsx`,
    archivo_gestion: `reporte_gestion_${dd}.xlsx`,
    filas_productividad: prodRows,
    filas_gestion: gestRows,
    nota: 'Exportacion XLSX y carga SFTP ejecutadas',
    advertencia: gestRows === 0 ? 'Rama gestion sin ejecucion o sin datos' : null,
    ejecutar_descarga: cfg.report.ejecutarDescargaLlamadas
  }
}];

