const cfg = $items('CONFIG INICIAL', 0, 0)[0].json.cfg;
const apiKey = cfg.vapi.apiKey;
const assistants = [cfg.vapi.assistants.PREVENTIVA, cfg.vapi.assistants.COBROS];

const forDate = cfg.report.forDate;
const createdAtGe = new Date(`${forDate}T00:00:00.000-05:00`).toISOString();
const createdAtLe = new Date(`${forDate}T23:59:59.999-05:00`).toISOString();

let allCalls = [];

for (const assistantId of assistants) {
  if (!assistantId) continue;
  const options = {
    method: 'GET',
    url: 'https://api.vapi.ai/call',
    qs: {
      assistantId: assistantId,
      createdAtGe: createdAtGe,
      createdAtLe: createdAtLe,
      limit: 1000
    },
    headers: { 'Authorization': `Bearer ${apiKey}` },
    json: true
  };

  try {
    const response = await this.helpers.request(options);
    const results = response.results || response;
    if (Array.isArray(results)) {
      results.forEach(c => {
        allCalls.push({
          call_id: c.id,
          agente_tipo: assistantId === cfg.vapi.assistants.PREVENTIVA ? 'PREVENTIVA' : 'COBROS',
          exportFolderPath: cfg.report.exportFolderPath,
          createdAt: (c.createdAt || '').replace(/:/g, '-')
        });
      });
    }
  } catch (err) {
    console.error("Error fetching Vapi calls", err);
  }
}

if (allCalls.length === 0) {
  return []; 
}
// Filtrar IDs ya descargados en SFTP
let descargados = [];
try {
  const sftpItem = $items('EXTRAER IDS DESCARGADOS', 0, 0);
  if (sftpItem && sftpItem.json && Array.isArray(sftpItem.json.descargados)) {
    descargados = sftpItem.json.descargados;
  }
} catch (e) {
  // nodo no ejecutado o error, continuar sin filtrar
}
const descargadosSet = new Set(descargados);
const pendientes = allCalls.filter(c => !descargadosSet.has(c.call_id));
return pendientes.map(c => ({ json: c }));

const details = $json;
const artifact = details.artifact || {};
const audioUrl = artifact.recordingUrlMp3 
  || artifact.mp3RecordingUrl 
  || artifact.recordingUrl 
  || artifact.stereoRecordingUrl 
  || null;

let ext = 'wav';
if (audioUrl && audioUrl.toLowerCase().includes('.mp3')) {
  ext = 'mp3';
}

const batchItem = $('SPLIT DESCARGAS').first().json;

return [{
  json: {
    call_id: batchItem.call_id,
    mp3_url: audioUrl,
    has_audio: !!audioUrl,
    ext: ext,
    exportFolderPath: batchItem.exportFolderPath,
    createdAt: batchItem.createdAt
  }
}];

const descargados = ($input.all() || [])
  .map(item => {
    const name = (item.json && item.json.name) || item.json || '';
    if (!name) return null;
    const lastUnderscore = name.lastIndexOf('_');
    const lastDot = name.lastIndexOf('.');
    if (lastUnderscore < 0 || lastDot < 0) return null;
    return name.substring(lastUnderscore + 1, lastDot);
  })
  .filter(id => id && id.length > 0 && id !== '.keep');

return [{ json: { descargados } }];

const binaryData = Buffer.from('', 'utf-8');
return [{
  json: {},
  binary: {
    data: {
      data: binaryData.toString('base64'),
      mimeType: 'application/octet-stream',
      fileName: '.keep',
      fileSize: binaryData.length
    }
  }
}];
